const mobileMenuBtn=document.getElementById("mobile-menu-btn"),nav=document.getElementById("nav");mobileMenuBtn.addEventListener("click",(()=>{nav.classList.toggle("active");const e=mobileMenuBtn.querySelector("i");nav.classList.contains("active")?(e.classList.remove("fa-bars"),e.classList.add("fa-xmark")):(e.classList.remove("fa-xmark"),e.classList.add("fa-bars"))})),document.querySelectorAll(".nav-list a").forEach((e=>{e.addEventListener("click",(()=>{nav.classList.remove("active");const e=mobileMenuBtn.querySelector("i");e.classList.remove("fa-xmark"),e.classList.add("fa-bars")}))})),document.querySelectorAll(".hour-btn").forEach((e=>{e.addEventListener("click",(()=>{document.querySelectorAll(".hour-btn").forEach((e=>e.classList.remove("active"))),e.classList.add("active")}))}));const header=document.querySelector(".header");window.addEventListener("scroll",(()=>{window.scrollY>50?header.style.padding="10px 0":header.style.padding="15px 0"}));const style=document.createElement("style");style.textContent="@media (max-width: 992px) { .nav.active { display: block; position: absolute; top: 100%; left: 0; width: 100%; background: var(--black); padding: 30px 20px; box-shadow: 0 10px 30px rgba(0,0,0,0.5); border-bottom: 2px solid var(--primary); z-index: 1000; } .nav.active .nav-list { flex-direction: column; gap: 20px; text-align: center; } .nav.active .nav-list a { color: #ddd; font-size: 1.1rem; padding: 10px; display: block; } .nav.active .nav-list a:hover { color: var(--primary); } }",document.head.appendChild(style);
